// Try to load scraped feed data via fs (server-side only, safe in Next.js API routes)
async function loadScrapedFeed(): Promise<Record<string, unknown>[]> {
  try {
    const fs   = await import('fs');
    const path = await import('path');

    const root        = path.resolve(process.cwd(), '..', 'data', 'hungary', 'intelligence');
    const foreignPath = path.join(root, 'foreign', 'feed.json');
    const socialPath  = path.join(root, 'social',  'feed.json');

    const readJson = (p: string): Record<string, unknown>[] => {
      try {
        const raw = fs.readFileSync(p, 'utf-8');
        const parsed = JSON.parse(raw);
        return Array.isArray(parsed.items) ? parsed.items : [];
      } catch { return []; }
    };

    return [...readJson(foreignPath), ...readJson(socialPath)];
  } catch {
    return [];
  }
}

export async function GET(request: NextRequest) {
  const { searchParams } = new URL(request.url);
  const topic  = searchParams.get('topic') ?? 'all';
  const lang   = searchParams.get('lang') ?? 'all';
  const type   = searchParams.get('type') ?? 'all';
  const limit  = Math.min(parseInt(searchParams.get('limit') ?? '20'), 50);

  let items = await loadScrapedFeed();

  // Fall back to curated items if no scraped data yet
  if (items.length === 0) {
    items = CURATED_FALLBACK as Record<string, unknown>[];
  } else {
    // Prepend curated to fill any gaps
    const curated = CURATED_FALLBACK.map(c => ({ ...c, is_curated: true }));
    items = [...curated, ...items];
  }

  // Deduplicate by url
  const seen = new Set<string>();
  items = items.filter(item => {
    const url = item.url as string;
    if (!url || seen.has(url)) return false;
    seen.add(url);
    return true;
  });

  // Filter
  if (topic !== 'all') {
    items = items.filter(i => i.topic === topic);
  }
  if (lang !== 'all') {
    items = items.filter(i => i.language === lang);
  }
  if (type !== 'all') {
    items = items.filter(i => i.content_type === type || (type === 'social' && (i as Record<string, unknown>).is_sentiment));
  }

  // Sort: high-weight press first, then by recency
  const weightOrder = { high: 0, medium: 1, low: 2 };
  items.sort((a, b) => {
    const wa = weightOrder[a.weight as keyof typeof weightOrder] ?? 2;
    const wb = weightOrder[b.weight as keyof typeof weightOrder] ?? 2;
    if (wa !== wb) return wa - wb;
    return (b.fetched_at as string ?? '').localeCompare(a.fetched_at as string ?? '');
  });

  return NextResponse.json({
    items: items.slice(0, limit),
    total: items.length,
    sections: TOPIC_SECTIONS,
    generated_at: new Date().toISOString(),
  });
}
